---
import type { CollectionEntry } from "astro:content";
import { getCollection, render } from "astro:content";
import Breadcrumb from "../../components/Breadcrumb.astro";
import ShareButtons from "../../components/blog/ShareButtons.astro";
import PostNavigation from "../../components/PostNavigation.astro";
import RelatedPosts from "../../components/RelatedPosts.astro";
import BackToTop from "../../components/ui/BackToTop.astro";
import Tag from "../../components/ui/Tag.astro";
import { SITE } from "../../config/site";
import Layout from "../../layouts/Layout.astro";
import { formatDate } from "../../utils/date";
import { formatReadingTime, getReadingTime } from "../../utils/reading-time";
import { generateBreadcrumbSchema, stringifySchema } from "../../utils/schema";

export async function getStaticPaths() {
	const blogPosts = await getCollection("blog");
	// 公開日でソート（新しい順）
	const sortedPosts = blogPosts.sort(
		(a, b) => b.data.date.getTime() - a.data.date.getTime(),
	);

	return sortedPosts.map((post, index) => {
		// 前後の記事（時系列順: prev=古い、next=新しい）
		const prevPost = sortedPosts[index + 1];
		const nextPost = sortedPosts[index - 1];

		// 関連記事（同じタグを持つ記事、最大3件）
		const currentTags = post.data.tags || [];
		const relatedPosts = sortedPosts
			.filter((p) => p.id !== post.id)
			.filter((p) => p.data.tags?.some((t: string) => currentTags.includes(t)))
			.slice(0, 3);

		return {
			params: { id: post.id },
			props: {
				post,
				prevPost: prevPost
					? { id: prevPost.id, title: prevPost.data.title }
					: undefined,
				nextPost: nextPost
					? { id: nextPost.id, title: nextPost.data.title }
					: undefined,
				relatedPosts,
			},
		};
	});
}

const { post, prevPost, nextPost, relatedPosts } = Astro.props;
const { Content } = await render(post);
const canonicalURL = new URL(Astro.url.pathname, Astro.site);
const readingTime = getReadingTime(post.body || "");
const readingTimeText = formatReadingTime(readingTime);
const publishedTime = post.data.date.toISOString();
const modifiedTime = post.data.updatedDate
	? post.data.updatedDate.toISOString()
	: publishedTime;
const ogImageURL = new URL(`/og/blog/${post.id}.png`, Astro.site);
const blogSchema = {
	"@context": "https://schema.org",
	"@type": "BlogPosting",
	headline: post.data.title,
	description: post.data.excerpt,
	datePublished: publishedTime,
	dateModified: modifiedTime,
	author: {
		"@type": "Person",
		name: SITE.author,
		url: Astro.site?.href,
	},
	image: ogImageURL.href,
	mainEntityOfPage: canonicalURL.href,
	inLanguage: SITE.lang,
};
const breadcrumbItems = [
	{ label: "ホーム", href: "/" },
	{ label: "ブログ", href: "/blog" },
	{ label: post.data.title },
];
const siteUrl = Astro.site?.href || SITE.url;
---

<Layout
  title={`${post.data.title} | Blog | ${SITE.name}`}
  description={post.data.excerpt}
  ogType="article"
  ogImage={ogImageURL.href}
  ogImageAlt={post.data.title}
>
  <Fragment slot="head">
    <meta property="article:author" content={SITE.author} />
    <meta property="article:published_time" content={publishedTime} />
    {
      post.data.updatedDate && (
        <meta property="article:modified_time" content={modifiedTime} />
      )
    }
    <script
      type="application/ld+json"
      set:html={stringifySchema(blogSchema)}
    />
    <script
      type="application/ld+json"
      set:html={stringifySchema(generateBreadcrumbSchema(breadcrumbItems, siteUrl))}
    />
  </Fragment>
  <main class="mx-auto max-w-4xl px-6 py-12">
    <Breadcrumb items={breadcrumbItems} />
    <div class="mb-8">
      <a
        href="/blog"
        class="mb-4 inline-block text-sm text-neutral-600 hover:text-neutral-900"
      >
        ← Blog一覧へ戻る
      </a>
      <h1 class="mb-4 text-4xl font-bold">{post.data.title}</h1>
      <div class="flex flex-wrap items-center gap-4 text-neutral-600">
        <time>
          {formatDate(post.data.date)}
          {
            post.data.updatedDate && (
              <span class="ml-2 text-sm">
                (更新: {formatDate(post.data.updatedDate)})
              </span>
            )
          }
        </time>
        <span class="text-sm">{readingTimeText}</span>
        {
          post.data.tags && post.data.tags.length > 0 && (
            <div class="flex flex-wrap gap-2">
              {post.data.tags.map((tag: string) => (
                <Tag>{tag}</Tag>
              ))}
            </div>
          )
        }
      </div>
    </div>

    <article class="prose prose-lg max-w-none">
      <Content />
    </article>

    <div class="mt-12 border-t border-neutral-200 pt-8">
      <ShareButtons url={canonicalURL.href} title={post.data.title} />
    </div>

    <PostNavigation prevPost={prevPost} nextPost={nextPost} />

    <RelatedPosts posts={relatedPosts} />
  </main>
  <BackToTop />
</Layout>

<script>
  // Add copy buttons to all code blocks
  const copyIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path d="M7 3.5A1.5 1.5 0 0 1 8.5 2h3.879a1.5 1.5 0 0 1 1.06.44l3.122 3.12A1.5 1.5 0 0 1 17 6.622V12.5a1.5 1.5 0 0 1-1.5 1.5h-1v-3.379a3 3 0 0 0-.879-2.121L10.5 5.379A3 3 0 0 0 8.379 4.5H7v-1Z" /><path d="M4.5 6A1.5 1.5 0 0 0 3 7.5v9A1.5 1.5 0 0 0 4.5 18h7a1.5 1.5 0 0 0 1.5-1.5v-5.879a1.5 1.5 0 0 0-.44-1.06L9.44 6.439A1.5 1.5 0 0 0 8.378 6H4.5Z" /></svg>`;
  const copiedIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clip-rule="evenodd" /></svg>`;

  document.querySelectorAll(".prose pre").forEach((pre) => {
    const button = document.createElement("button");
    button.className = "copy-button";
    button.innerHTML = copyIcon;
    button.addEventListener("click", async () => {
      const code = pre.querySelector("code");
      if (code) {
        await navigator.clipboard.writeText(code.textContent || "");
        button.classList.add("copied");
        button.innerHTML = copiedIcon;
        setTimeout(() => {
          button.classList.remove("copied");
          button.innerHTML = copyIcon;
        }, 2000);
      }
    });
    pre.appendChild(button);
  });
</script>

