Using regular expressions to parse HTML is generally discouraged as it can be very brittle and break with minor changes to the HTML structure (e.g., attribute order, quote types). A dedicated HTML parser is much more robust.

Additionally, the current implementation silently swallows any errors that occur during the fetch or parsing process in a `catch` block. This makes debugging difficult if a link card fails to render. It's better to log these errors.

I suggest refactoring this utility to use an HTML parser like `node-html-parser` and adding proper error handling. You'll need to add the dependency first: `pnpm add node-html-parser`.

Here's a suggested implementation that addresses these points and also improves the user-agent string to be more descriptive:

```typescript
import { parse } from 'node-html-parser';
import type { HTMLElement } from 'node-html-parser';

export interface OgpData {
	title: string;
	description: string;
	image: string;
	favicon: string;
	url: string;
	domain: string;
}

function extractMetaContent(root: HTMLElement, property: string): string {
	const element = root.querySelector(`meta[property="${property}"], meta[name="${property}"]`);
	return element?.getAttribute('content') ?? '';
}

function extractTitle(root: HTMLElement): string {
	return root.querySelector('title')?.textContent ?? '';
}

export async function fetchOgpData(url: string): Promise<OgpData> {
	const domain = new URL(url).hostname.replace("www.", "");
	const favicon = `https://www.google.com/s2/favicons?domain=${domain}&sz=32`;

	try {
		const response = await fetch(url, {
			headers: {
				"User-Agent": "bot (portfolio-ogp-fetcher; +https://github.com/ta93abe/portfolio)",
			},
		});

		if (!response.ok) {
			throw new Error(`Failed to fetch ${url}: ${response.status} ${response.statusText}`);
		}

		const html = await response.text();
		const root = parse(html);

		const ogTitle = extractMetaContent(root, "og:title") || extractTitle(root);
		const ogDescription =
			extractMetaContent(root, "og:description") ||
			extractMetaContent(root, "description");
		const ogImage = extractMetaContent(root, "og:image");

		return {
			title: ogTitle || domain,
			description: ogDescription,
			image: ogImage,
			favicon,
			url,
			domain,
		};
	} catch (error) {
		console.error(`[fetchOgpData] Failed to fetch OGP data for ${url}:`, error);
		return {
			title: domain,
			description: "",
			image: "",
			favicon,
			url,
			domain,
		};
	}
}
